    store: &StateStore,
    closed_task_id: &str,
) -> Result<bool, String> {
    let Some(mut receipt) = store
        .latest_run_graph_dispatch_receipt()
        .await
        .map_err(|error| format!("Failed to load latest run-graph dispatch receipt: {error}"))?
    else {
