                    .to_string(),
            ),
            true,
            Vec::new(),
        ),
        "spec-pack" => {
            let blockers = vec![
                blocker_code_value(BlockerCode::PendingDesignFinalize)
                    .expect("pending design finalize should stay registry-backed"),
                blocker_code_value(BlockerCode::PendingSpecTaskClose)
